instance GearboxEncoderAngleData : DTDFVocab:Data [
    base:desc "Raw gearbox encoder angle r_out"
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance TorqueData : DTDFVocab:Data [
    base:desc "Derived torque τ calculated from I_M, r_M and r_out"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity ω calculated from encoder angle rate"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

