    base:desc "Friction model with Stribeck effect for gearbox"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance DahlFrictionModel : DTDFVocab:Model [
    base:desc "Dahl friction model for gearbox"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

instance LuGreFrictionModel : DTDFVocab:Model [
    base:desc "LuGre friction model for gearbox"
    DTDFVocab:inputTo SimulinkSimulationEnabler
]

