                     DataAggregationService,
                     DashboardVisualizationService
]

instance SimulinkSimulationEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment for friction and calculation models"
    DTDFVocab:enables RealTimeFrictionIdentificationService,
                     ModelSwappingService,
                     ParameterUpdateService
]

